import { useEffect, useMemo, useState } from 'react';
import { getProduits } from '../services/stockApi';
import { Search, Plus, Edit3, Trash2, Upload, Download } from 'lucide-react';
import Spinner from '../components/Spinner';
import toast from 'react-hot-toast';

const INITIAL_FORM = {
  id: null,
  reference: '',
  name: '',
  category: '',
  price: 0,
  stock: 0,
  alertThreshold: 10,
  unit: 'pcs',
};

function getStatus(stock, alertThreshold) {
  if (stock <= 0) return { label: 'Rupture', badge: 'badge-red' };
  if (stock <= alertThreshold) return { label: 'Stock bas', badge: 'badge-yellow' };
  return { label: 'OK', badge: 'badge-green' };
}

function toCsv(products) {
  const headers = ['id', 'reference', 'name', 'category', 'price', 'stock', 'alertThreshold', 'unit'];
  const lines = [headers.join(',')];
  products.forEach((p) => {
    lines.push([
      p.id,
      p.reference,
      p.name,
      p.category,
      p.price,
      p.stock,
      p.alertThreshold,
      p.unit,
    ].map(v => `"${String(v ?? '')}"`).join(','));
  });
  return lines.join('\n');
}

function parseCsv(content) {
  const lines = content
    .split(/\r?\n/)
    .map(line => line.trim())
    .filter(line => line);

  if (!lines.length) return [];

  const header = lines[0].split(',').map(h => h.replace(/"/g, '').trim().toLowerCase());
  const getIndex = key => header.indexOf(key);
  const required = ['reference', 'name', 'price', 'stock'];
  if (!required.every(f => getIndex(f) > -1)) {
    throw new Error('CSV invalide : colonnes manquantes.');
  }

  return lines.slice(1).map((line, idx) => {
    const cols = line.split(',').map(c => c.replace(/"/g, '').trim());
    return {
      id: Number(cols[getIndex('id')]) || Date.now() + idx,
      reference: cols[getIndex('reference')] || `REF-${Date.now() + idx}`,
      name: cols[getIndex('name')] || 'Produit inconnu',
      category: cols[getIndex('category')] || 'Général',
      price: Number(cols[getIndex('price')]) || 0,
      stock: Number(cols[getIndex('stock')]) || 0,
      alertThreshold: Number(cols[getIndex('alertthreshold')]) || 10,
      unit: cols[getIndex('unit')] || 'pcs',
    };
  });
}

export default function Products() {
  const [produits, setProduits] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState(INITIAL_FORM);

  useEffect(() => {
    getProduits()
      .then(r => {
        const data = (r.data || []).map((p) => ({
          id: p.id,
          reference: p.reference || `REF-${p.id ?? Date.now()}`,
          name: p.name,
          category: p.category || 'Général',
          price: Number(p.price || 0),
          stock: Number(p.stock || 0),
          alertThreshold: Number(p.alertThreshold || 10),
          unit: p.unit || 'pcs',
        }));
        setProduits(data);
      })
      .catch(() => toast.error('Erreur lors du chargement des produits.'))
      .finally(() => setLoading(false));
  }, []);

  const categories = useMemo(() => {
    const set = new Set(produits.map(p => p.category || 'Général'));
    return Array.from(set);
  }, [produits]);

  const filteredProducts = useMemo(() => {
    const q = search.toLowerCase();
    return produits.filter((p) => {
      const matchText = [p.name, p.reference].join(' ').toLowerCase().includes(q);
      const matchCategory = !categoryFilter || p.category === categoryFilter;
      return matchText && matchCategory;
    });
  }, [produits, search, categoryFilter]);

  const openNew = () => {
    setForm(INITIAL_FORM);
    setModalOpen(true);
  };

  const openEdit = (product) => {
    setForm({ ...product });
    setModalOpen(true);
  };

  const handleDelete = (id) => {
    if (window.confirm('Supprimer ce produit ?')) {
      setProduits(cur => cur.filter(p => p.id !== id));
      toast.success('Produit supprimé.');
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.name.trim() || !form.reference.trim()) {
      return toast.error('Le nom et la référence sont obligatoires.');
    }
    const normalized = {
      ...form,
      name: form.name.trim(),
      reference: form.reference.trim(),
      category: form.category.trim() || 'Général',
      price: Number(form.price) || 0,
      stock: Number(form.stock) || 0,
      alertThreshold: Number(form.alertThreshold) || 0,
      unit: form.unit.trim() || 'pcs',
    };

    if (normalized.id) {
      setProduits(cur => cur.map(p => (p.id === normalized.id ? normalized : p)));
      toast.success('Produit modifié.');
    } else {
      const newProduct = { ...normalized, id: Date.now() };
      setProduits(cur => [newProduct, ...cur]);
      toast.success('Produit ajouté.');
    }

    setModalOpen(false);
  };

  const handleImport = (event) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = parseCsv(e.target.result);
        setProduits(cur => {
          const existing = new Map(cur.map(p => [String(p.reference).toLowerCase(), p]));
          imported.forEach((p) => { existing.set(String(p.reference).toLowerCase(), p); });
          return Array.from(existing.values());
        });
        toast.success('Import CSV réussi.');
      } catch (err) {
        toast.error(err.message || 'Erreur d’import CSV.');
      }
    };
    reader.readAsText(file, 'UTF-8');
    event.target.value = null;
  };

  const handleExport = () => {
    const csv = toCsv(filteredProducts.length ? filteredProducts : produits);
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'produits.csv';
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h2>Produits</h2>
          <p>{produits.length} produit(s) référencé(s)</p>
        </div>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <button className="btn btn-primary" onClick={openNew}>
            <Plus /> Nouveau
          </button>
          <label className="btn btn-ghost" style={{ cursor: 'pointer' }}>
            <Upload /> Import CSV
            <input type="file" accept=".csv,text/csv" onChange={handleImport} style={{ display: 'none' }} />
          </label>
          <button className="btn btn-ghost" onClick={handleExport}><Download /> Export CSV</button>
        </div>
      </div>

      <div className="card" style={{ marginBottom: 16, alignItems: 'flex-end', gap: 12 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, width: 320 }}>
          <Search />
          <input
            className="form-group"
            style={{ width: '100%', borderRadius: '8px', padding: '9px 10px', border: '1px solid var(--border)' }}
            placeholder="Rechercher par nom ou référence..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <select
          className="form-group"
          style={{ width: 220 }}
          value={categoryFilter}
          onChange={(e) => setCategoryFilter(e.target.value)}
        >
          <option value="">Toutes catégories</option>
          {categories.map((cat) => (<option key={cat} value={cat}>{cat}</option>))}
        </select>
      </div>

      {loading ? <Spinner /> : (
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Référence</th>
                <th>Nom</th>
                <th>Catégorie</th>
                <th style={{ textAlign: 'right' }}>Prix</th>
                <th style={{ textAlign: 'right' }}>Stock</th>
                <th>Statut</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredProducts.length === 0 ? (
                <tr>
                  <td colSpan={7} style={{ textAlign: 'center', padding: '20px' }}>
                    Aucun produit correspondant.
                  </td>
                </tr>
              ) : filteredProducts.map((p) => {
                const status = getStatus(p.stock, p.alertThreshold);
                return (
                  <tr key={p.id}>
                    <td>{p.reference}</td>
                    <td>{p.name}</td>
                    <td>{p.category}</td>
                    <td style={{ textAlign: 'right' }}>{p.price.toFixed(2)} €</td>
                    <td style={{ textAlign: 'right' }}>{p.stock} {p.unit}</td>
                    <td>
                      <span className={`badge ${status.badge}`}>{status.label}</span>
                    </td>
                    <td>
                      <button className="btn btn-ghost" onClick={() => openEdit(p)}><Edit3 size={14} /> Modifier</button>
                      <button className="btn btn-danger" style={{ marginLeft: 6 }} onClick={() => handleDelete(p.id)}><Trash2 size={14} /> Supprimer</button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {modalOpen && (
        <div className="modal-overlay" onClick={() => setModalOpen(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <h3>{form.id ? 'Modifier le produit' : 'Ajouter un produit'}</h3>
            <form onSubmit={handleSubmit}>
              <div className="form-grid" style={{ marginTop: 14 }}>
                <div className="form-group">
                  <label>Référence</label>
                  <input
                    value={form.reference}
                    onChange={(e) => setForm({ ...form, reference: e.target.value })}
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Nom</label>
                  <input
                    value={form.name}
                    onChange={(e) => setForm({ ...form, name: e.target.value })}
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Catégorie</label>
                  <input
                    value={form.category}
                    onChange={(e) => setForm({ ...form, category: e.target.value })}
                    placeholder="Ex: Électronique"
                  />
                </div>
                <div className="form-group">
                  <label>Prix (€)</label>
                  <input type="number" step="0.01" min="0"
                    value={form.price}
                    onChange={(e) => setForm({ ...form, price: e.target.value })}
                  />
                </div>
                <div className="form-group">
                  <label>Stock</label>
                  <input type="number" min="0"
                    value={form.stock}
                    onChange={(e) => setForm({ ...form, stock: e.target.value })}
                  />
                </div>
                <div className="form-group">
                  <label>Seuil d'alerte</label>
                  <input type="number" min="0"
                    value={form.alertThreshold}
                    onChange={(e) => setForm({ ...form, alertThreshold: e.target.value })}
                  />
                </div>
                <div className="form-group">
                  <label>Unité</label>
                  <input
                    value={form.unit}
                    onChange={(e) => setForm({ ...form, unit: e.target.value })}
                  />
                </div>
              </div>
              <div className="form-actions">
                <button type="button" className="btn btn-ghost" onClick={() => setModalOpen(false)}>Annuler</button>
                <button type="submit" className="btn btn-primary">{form.id ? 'Enregistrer' : 'Ajouter'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
